props.extensibilityCode:
// Textarea com contador de caracteres acessível
const [value, setValue] = useState('');
const max = 500;

<div className="space-y-2">
  <Label htmlFor="description">Descrição</Label>
  <Textarea
    id="description"
    value={value}
    onChange={(e) => setValue(e.target.value)}
    placeholder="ex: Descreva o produto..."
    className="resize-y min-h-[120px]"
    maxLength={max}
  />
  <div className="flex justify-between text-xs text-muted-foreground">
    <span>Descreva com clareza.</span>
    <span
      aria-live="polite"
      aria-label={`${value.length} de ${max} caracteres usados`}
    >
      {value.length}/{max}
    </span>
  </div>
</div>

tokens.customizationCode:
/* Altura mínima customizada */
[data-slot="textarea"] {
  min-height: 180px;
}

/* Borda colorida quando inválido + foco */
[data-slot="textarea"][aria-invalid="true"]:focus-visible {
  --ring-color: hsl(var(--destructive));
}

